import hashlib
import json
import os
import subprocess
import sys
import tempfile
from pathlib import Path

AC_UID = "ac11-z-suffix-expiry-parsing"
AC_TYPE = "data"

SCRIPT = str(Path(__file__).parent.parent.parent.parent / "scripts" / "execute-push.py")
REPO_ROOT = str(Path(__file__).parent.parent.parent.parent)


def _compute_repo_hash() -> str:
    real_root = os.path.realpath(REPO_ROOT)
    return hashlib.sha256(real_root.encode()).hexdigest()[:16]


def _get_git_info() -> tuple:
    branch = subprocess.run(
        ["git", "rev-parse", "--abbrev-ref", "HEAD"],
        capture_output=True, text=True, check=True, cwd=REPO_ROOT,
    ).stdout.strip()
    head_sha = subprocess.run(
        ["git", "rev-parse", "HEAD"],
        capture_output=True, text=True, check=True, cwd=REPO_ROOT,
    ).stdout.strip()
    return branch, head_sha


def test_AC11():
    """
    GIVEN: A valid grant exists with expires_at in format YYYY-MM-DDTHH:MM:SSZ (trailing Z, as written by push-analyst), and all other fields correct, verdict=approved
    WHEN:  python3 scripts/execute-push.py --request-id <request_id> --repo-hash <repo_hash> --remote origin is run (with fake push.sh setup as in AC10)
    THEN:  Script correctly parses the Z-suffix ISO-8601 timestamp and does NOT exit with expiry error; proceeds to sentinel-write and exec
    """
    repo_hash = _compute_repo_hash()
    branch, head_sha = _get_git_info()
    session_id = "testsid"
    request_id = "ac11req789"
    remote = "origin"

    with tempfile.TemporaryDirectory() as tmp_home:
        # Create fake push.sh
        hooks_dir = Path(tmp_home) / ".claude" / "hooks"
        hooks_dir.mkdir(parents=True)
        push_sh = hooks_dir / "push.sh"
        push_sh.write_text("#!/bin/sh\nexit 0\n")
        push_sh.chmod(0o755)

        # Write the grant file with Z-suffix expires_at
        grant_dir = f"/tmp/agentic-commit/push-analyst/{repo_hash}/{session_id}"
        grant_path = f"{grant_dir}/{request_id}.json"
        branch_encoded = branch.replace("/", "__")
        sentinel_path = f"/tmp/agentic-commit/push-analyst/{repo_hash}/{branch_encoded}-chainB.validated.sentinel.json"

        grant = {
            "nonce": request_id,
            "branch": branch,
            "head_sha": head_sha,
            "remote_name": remote,
            "session_id": session_id,
            "verdict": "approved",
            "risks": [],
            "expires_at": "2099-01-01T00:00:00Z",  # Z-suffix format
        }

        os.makedirs(grant_dir, exist_ok=True)
        # Remove stale sentinel if present
        if os.path.exists(sentinel_path):
            os.unlink(sentinel_path)

        try:
            with open(grant_path, "w") as fp:
                json.dump(grant, fp)

            env = {
                **os.environ,
                "CLAUDE_SESSION_ID": session_id,
                "HOME": tmp_home,
            }
            result = subprocess.run(
                [sys.executable, SCRIPT,
                 "--request-id", request_id,
                 "--repo-hash", repo_hash,
                 "--remote", remote],
                capture_output=True,
                text=True,
                env=env,
                cwd=REPO_ROOT,
            )

            # Script must NOT fail with an expiry error
            assert "expired" not in result.stderr, (
                f"Script incorrectly reported expiry error for Z-suffix timestamp.\n"
                f"stderr: {result.stderr}"
            )
            assert "not valid ISO-8601" not in result.stderr, (
                f"Script failed to parse Z-suffix ISO-8601 timestamp.\n"
                f"stderr: {result.stderr}"
            )

            # Script should succeed (exit 0 from push.sh)
            assert result.returncode == 0, (
                f"Expected exit 0 (push.sh executed), got {result.returncode}.\n"
                f"stdout: {result.stdout}\nstderr: {result.stderr}"
            )

            # Sentinel must exist, confirming the script proceeded past expiry check
            assert os.path.exists(sentinel_path), (
                f"Chain-B sentinel not written — script may have aborted before exec: {sentinel_path}"
            )

        finally:
            if os.path.exists(grant_path):
                os.unlink(grant_path)
